-- Big Five Personality Assessment: assessment row + 96 items
values ('big-five', 'Big Five Personality', 'The five-factor model, with six expanded facets and a full personal report.', 'personal', 1, 5, 15, 16, true, false, true, 'standard', false, 0, '[]'::jsonb, false)
on conflict (slug) do update set name=excluded.name, subtitle=excluded.subtitle, category=excluded.category, scale_min=excluded.scale_min, scale_max=excluded.scale_max, estimated_minutes=excluded.estimated_minutes, questions_per_page=excluded.questions_per_page, is_published=excluded.is_published;

delete from items where assessment_id = (select id from assessments where slug='big-five');

